using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet("{url}")]
    public async Task<IActionResult> Get([FromRoute] string url)
    {
        var response = await _httpClient.GetAsync(url);

        response.EnsureSuccessStatusCode();

        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }

    [HttpPost("{url}")]
    public async Task<IActionResult> Post([FromRoute] string url, [FromBody] string body)
    {
        var content = new StringContent(body, Encoding.UTF8, "text/plain");
        var response = await _httpClient.PostAsync(url, content);

        response.EnsureSuccessStatusCode();

        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }

    // Add more methods for other HTTP verbs as needed
}
